import React, { useEffect, useState } from 'react';
import axios from '../api/axiosConfig';

function AdminDashboardPage({ user }) {
  const [stats, setStats] = useState(null);
  const [complaints, setComplaints] = useState([]);
  const [category, setCategory] = useState('');
  const [status, setStatus] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const fetchStats = async () => {
    try {
      const response = await axios.get('/admin/stats');
      setStats(response.data);
    } catch (err) {
      console.error(err);
    }
  };

  const fetchComplaints = async () => {
    setLoading(true);
    setError('');
    try {
      const query = new URLSearchParams();
      if (category) query.append('category', category);
      if (status) query.append('status', status);
      const response = await axios.get(`/admin/complaints?${query.toString()}`);
      setComplaints(response.data);
    } catch (err) {
      setError('Unable to load complaints');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (!user || user.role !== 'admin') return;
    fetchStats();
    fetchComplaints();
  }, [user]);

  const updateStatus = async (id, newStatus) => {
    try {
      await axios.patch(`/admin/complaints/${id}/status`, { status: newStatus });
      fetchStats();
      fetchComplaints();
    } catch (err) {
      setError('Unable to update status');
    }
  };

  if (!user || user.role !== 'admin') {
    return <div className="card">Admin login is required to view this page.</div>;
  }

  return (
    <div className="card">
      <h2>Admin Dashboard</h2>
      <div className="summary-row">
        <div className="summary-box">
          <strong>Total</strong>
          <span>{stats?.total ?? '-'}</span>
        </div>
        <div className="summary-box">
          <strong>Pending</strong>
          <span>{stats?.pending ?? '-'}</span>
        </div>
        <div className="summary-box">
          <strong>In Progress</strong>
          <span>{stats?.inProgress ?? '-'}</span>
        </div>
        <div className="summary-box">
          <strong>Resolved</strong>
          <span>{stats?.resolved ?? '-'}</span>
        </div>
      </div>

      <div className="filter-row">
        <div>
          <label>Category</label>
          <select value={category} onChange={(e) => setCategory(e.target.value)}>
            <option value="">All</option>
            <option value="electrical">Electrical</option>
            <option value="water">Water</option>
            <option value="internet">Internet</option>
            <option value="cleaning">Cleaning</option>
            <option value="others">Others</option>
          </select>
        </div>
        <div>
          <label>Status</label>
          <select value={status} onChange={(e) => setStatus(e.target.value)}>
            <option value="">All</option>
            <option value="Pending">Pending</option>
            <option value="In Progress">In Progress</option>
            <option value="Resolved">Resolved</option>
          </select>
        </div>
        <button onClick={fetchComplaints}>Filter</button>
      </div>

      {error && <div className="error-box">{error}</div>}
      {loading && <div className="info-box">Loading complaints...</div>}
      <div className="table-scroll">
        <table>
          <thead>
            <tr>
              <th>Title</th>
              <th>Category</th>
              <th>User</th>
              <th>Status</th>
              <th>Date</th>
              <th>Action</th>
            </tr>
          </thead>
          <tbody>
            {complaints.map((item) => (
              <tr key={item._id}>
                <td>{item.title}</td>
                <td>{item.category}</td>
                <td>{item.userId?.email || item.userId?.name || 'Unknown'}</td>
                <td>{item.status}</td>
                <td>{new Date(item.createdAt).toLocaleDateString()}</td>
                <td>
                  <select
                    value={item.status}
                    onChange={(e) => updateStatus(item._id, e.target.value)}>
                    <option value="Pending">Pending</option>
                    <option value="In Progress">In Progress</option>
                    <option value="Resolved">Resolved</option>
                  </select>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

export default AdminDashboardPage;
